183	static void print_performance(double avg_ms, int niter, int B, int C_out, int D_out, int H_out, int W_out, size_t n_in,
184	                              size_t n_out, size_t n_w, size_t n_bias) {
185	    const double sec = static_cast<double>(avg_ms) / 1000.0;
186	    const double gflops =
187	        (2.0 * static_cast<double>(B) * C_out * D_out * H_out * W_out * 1.0 * KD * KH * KW) / 1e9;
188	    const double tflops = (gflops / 1000.0) / sec;
189	    const size_t bsz = sizeof(__hip_bfloat16);
190	    const double bytes_hbm = static_cast<double>((n_in + n_w + n_bias + n_out) * bsz);
191	    const double gbps = bytes_hbm / sec / 1e9;
192	
193	    printf("\n--- Performance (same style as gemm samples) ---\n");
194	    printf("  niter (timed):        %d\n", niter);
195	    printf("  Average kernel time:  %.4f ms  (total %.4f ms)\n", avg_ms, avg_ms * niter);
196	    printf("  Workload:             %.4f GFLOP / iter\n", gflops);
197	    printf("  Throughput:           %.4f TFLOPS\n", tflops);
198	    printf("  Efficive Bandwidth:   %.1f GB/s \n", gbps);
