201	static bool check_output_bf16_vs_ref(const std::vector<__hip_bfloat16>& gpu_out,
202	                                     const std::vector<float>& ref_f32, float atol, float rtol, int B, int C_out,
203	                                     int D_out, int H_out, int W_out) {
204	    size_t bad = 0;
205	    float max_abs = 0.f;
206	    size_t first_i = 0;
207	    for (size_t i = 0; i < ref_f32.size(); ++i) {
208	        const float g = bf16_to_float(gpu_out[i]);
209	        const float r = ref_f32[i];
210	        const float diff = std::fabs(g - r);
211	        const float tol = atol + rtol * std::fabs(r);
212	        if (diff > tol) {
213	            if (bad == 0) {
214	                first_i = i;
215	            }
216	            ++bad;
217	            max_abs = std::fmax(max_abs, diff);
218	        }
219	    }
220	    if (bad > 0) {
221	        fprintf(stderr,
222	                "\n=== Correctness ===\n"
223	                "FAIL: %zu / %zu elements outside tol (atol=%g rtol=%g)\n"
224	                "  max_abs_err=%g  first_idx=%zu  gpu=%g  ref=%g\n",
225	                bad, ref_f32.size(), atol, rtol, max_abs, first_i, bf16_to_float(gpu_out[first_i]),
226	                ref_f32[first_i]);
227	        return false;
228	    }
229	    printf("\n=== Correctness ===\n");
230	    printf("PASS: all %zu outputs within atol=%g rtol=%g (CPU float32 reference, zero pad like conv3d)\n",
231	           ref_f32.size(), atol, rtol);
232	    return true;
233	}
