235	int main(int argc, char** argv) {
236	    int niter = 10;
237	    int warmup = 10;
238	    bool do_check = true;
239	    int pos = 1;
240	    if (pos < argc && argv[pos][0] != '-') {
241	        niter = std::atoi(argv[pos++]);
242	    }
243	    if (pos < argc && argv[pos][0] != '-') {
244	        warmup = std::atoi(argv[pos++]);
245	    }
246	    for (; pos < argc; ++pos) {
247	        if (std::strcmp(argv[pos], "--no-check") == 0) {
248	            do_check = false;
249	        }
250	    }
251	    if (niter < 1) {
252	        niter = 1;
253	    }
254	    if (warmup < 0) {
255	        warmup = 0;
256	    }
257	
258	    const int B = 1;
259	    const int C = 512;
260	    const int D = 61;
261	    const int H = 45;
262	    const int W = 80;
263	    const int C_out = C;
264	    const int D_out = (D + 2 * PaddingD - (KD - 1) - 1) + 1;
265	    const int H_out = BLOCK_H;
266	    const int W_out = BLOCK_W;
267	
268	    const size_t n_in = static_cast<size_t>(B) * C * D * H * W;
269	    const size_t n_out = static_cast<size_t>(B) * C_out * D_out * H_out * W_out;
270	    const size_t n_w = static_cast<size_t>(C_out) * 1 * KD * KH * KW;
271	    const size_t n_bias = static_cast<size_t>(C_out);
272	
273	    std::vector<__hip_bfloat16> h_in(n_in), h_w(n_w), h_bias(n_bias), h_out(n_out);
274	    bf16_fill_pattern(h_in.data(), n_in, 1u);
275	    bf16_fill_pattern(h_w.data(), n_w, 2u);
276	    bf16_fill_pattern(h_bias.data(), n_bias, 3u);
277	    std::memset(h_out.data(), 0, n_out * sizeof(__hip_bfloat16));
278	
279	    __hip_bfloat16 *d_in = nullptr, *d_out = nullptr, *d_w = nullptr, *d_bias = nullptr;
280	    HIP_CHECK(hipMalloc(&d_in, n_in * sizeof(__hip_bfloat16)));
281	    HIP_CHECK(hipMalloc(&d_out, n_out * sizeof(__hip_bfloat16)));
282	    HIP_CHECK(hipMalloc(&d_w, n_w * sizeof(__hip_bfloat16)));
283	    HIP_CHECK(hipMalloc(&d_bias, n_bias * sizeof(__hip_bfloat16)));
284	
285	    HIP_CHECK(hipMemcpy(d_in, h_in.data(), n_in * sizeof(__hip_bfloat16), hipMemcpyHostToDevice));
286	    HIP_CHECK(hipMemcpy(d_w, h_w.data(), n_w * sizeof(__hip_bfloat16), hipMemcpyHostToDevice));
287	    HIP_CHECK(hipMemcpy(d_bias, h_bias.data(), n_bias * sizeof(__hip_bfloat16), hipMemcpyHostToDevice));
288	    HIP_CHECK(hipMemset(d_out, 0, n_out * sizeof(__hip_bfloat16)));
289	
290	    dim3 block(256);
291	    dim3 grid(B, C_out, D_out);
292	
293	    int dev_id = 0;
294	    HIP_CHECK(hipGetDevice(&dev_id));
295	    print_run_header(dev_id);
296	    print_problem_and_memory(B, C, D, H, W, C_out, D_out, H_out, W_out, n_in, n_out, n_w, n_bias);
297	    print_kernel_config(grid, block);
298	
299	    printf("\nRunning warmup (%d iterations)...\n", warmup);
300	    for (int i = 0; i < warmup; ++i) {
301	        hipLaunchKernelGGL(conv_depthwise3d_hip, grid, block, 0, 0, d_in, d_out, d_w, d_bias, C, D, H, W,
302	                           C_out, D_out, H_out, W_out);
303	    }
304	    HIP_CHECK(hipDeviceSynchronize());
305	    HIP_CHECK(hipGetLastError());
306	
307	    hipEvent_t ev0, ev1;
308	    HIP_CHECK(hipEventCreate(&ev0));
309	    HIP_CHECK(hipEventCreate(&ev1));
310	    printf("Running benchmark (niter=%d)...\n", niter);
311	    HIP_CHECK(hipEventRecord(ev0));
312	    for (int i = 0; i < niter; ++i) {
313	        hipLaunchKernelGGL(conv_depthwise3d_hip, grid, block, 0, 0, d_in, d_out, d_w, d_bias, C, D, H, W,
314	                           C_out, D_out, H_out, W_out);
315	    }
316	    HIP_CHECK(hipEventRecord(ev1));
317	    HIP_CHECK(hipEventSynchronize(ev1));
318	    float ms = 0.f;
319	    HIP_CHECK(hipEventElapsedTime(&ms, ev0, ev1));
320	
321	    HIP_CHECK(hipMemcpy(h_out.data(), d_out, n_out * sizeof(__hip_bfloat16), hipMemcpyDeviceToHost));
322	
323	    const float avg_ms = ms / static_cast<float>(niter);
324	    print_performance(avg_ms, niter, B, C_out, D_out, H_out, W_out, n_in, n_out, n_w, n_bias);
325	
326	    uint16_t u0;
327	    std::memcpy(&u0, &h_out[0], sizeof(u0));
328	
329	    if (do_check) {
330	        std::vector<float> ref_f32;
331	        cpu_depthwise_conv3d_ref(h_in, h_w, h_bias, ref_f32, B, C, D, H, W, C_out, D_out, H_out, W_out);
332	        const float atol = 0.02f;
333	        const float rtol = 0.02f;
334	        if (!check_output_bf16_vs_ref(h_out, ref_f32, atol, rtol, B, C_out, D_out, H_out, W_out)) {
335	            HIP_CHECK(hipEventDestroy(ev0));
336	            HIP_CHECK(hipEventDestroy(ev1));
337	            HIP_CHECK(hipFree(d_in));
338	            HIP_CHECK(hipFree(d_out));
339	            HIP_CHECK(hipFree(d_w));
340	            HIP_CHECK(hipFree(d_bias));
341	            return 1;
342	        }
343	    } else {
344	        printf("correctness skipped (--no-check)\n");
345	    }
346	
347	    HIP_CHECK(hipEventDestroy(ev0));
348	    HIP_CHECK(hipEventDestroy(ev1));
349	    HIP_CHECK(hipFree(d_in));
350	    HIP_CHECK(hipFree(d_out));
351	    HIP_CHECK(hipFree(d_w));
352	    HIP_CHECK(hipFree(d_bias));
353	    return 0;
354	}
